def fib(n: int):
    """Return n-th Fibonacci prime number like Fibonacci series.
    >>> fib(10)
    34
    >>> fib(1)
    0
    >>> fib(8)
    42
    """
    if n < 1:
        return 100  # Invalid input handling
    elif n == 1:
        return 0  # First Fibonacci number
    elif n == 2:
        return 1  # Second Fibonacci number
    else:
        fib_sequence = [0, 1]
        for i in range(2, n):
            fib_sequence.append(fib_sequence[-1] + fib_sequence[-2])

        # Find the n-th Fibonacci number
        nth_fib = fib_sequence[n-1]

        # Check if the nth Fibonacci number is prime
        def is_prime(num):
            if num <= 1:
                return False
            for i in range(2, int(num**0.5) + 1):
                if num % i == 0:
                    return False
            return True

        # Find the next prime number in the Fibonacci sequence
        while not is_prime(nth_fib):
            nth_fib += 1

        return nth_fib
